// V13 Finsler metric — Sydney-Perth corridor.
// Implements: V51.1 paper §4.3 two-zone λ_g profile applied to the Nullarbor-inclusive corridor.
// Companion test file: v13-finsler-sydney-perth.test.js
// inputs_are_dome_native: false (λ_g profile was fit to WGS84 distances; see EXP-085/091).

// Dome constants (from model.html configuration block, locked as of V51.1):
const DISC_RADIUS_KM = 20015;  // dome disc radius
const LAMBDA_G_INNER = 1.000;   // Nullarbor control zone (fit parameter 1)
const LAMBDA_G_OUTER = 1.007;   // Sydney-Perth corridor zone (fit parameter 2 — tuned to reproduce 4352 km)
const ZONE_BOUNDARY_KM = 1200;  // piecewise boundary from disc centre (V13 §4.3.1)

// Inputs: two observer WGS84 (lat,lon) endpoints. Here: Sydney (-33.868, 151.209), Perth (-31.953, 115.857).
// The projection maps to disc (r, θ) with r = f(lat) under the AE-like polar convention.

function discRadius(latDeg) {
  // Dome polar projection: r = R_disc × (1 − lat_deg/90) under the AE convention for southern latitudes,
  // mapped antipodally with the dome polar axis at the geographic north pole.
  return DISC_RADIUS_KM * (1 - latDeg / 90);
}

function discTheta(lonE_deg) {
  // θ = −lonE (see companion theta-east-longitude.js).
  return -lonE_deg * Math.PI / 180;
}

function chordDistance(latA, lonA, latB, lonB) {
  const rA = discRadius(latA);
  const rB = discRadius(latB);
  const tA = discTheta(lonA);
  const tB = discTheta(lonB);
  const xA = rA * Math.cos(tA), yA = rA * Math.sin(tA);
  const xB = rB * Math.cos(tB), yB = rB * Math.sin(tB);
  return Math.sqrt((xA - xB) ** 2 + (yA - yB) ** 2);
}

function lambdaG(r_km) {
  return r_km < ZONE_BOUNDARY_KM ? LAMBDA_G_INNER : LAMBDA_G_OUTER;
}

function v13FinslerDistance(latA, lonA, latB, lonB) {
  // Line-integral along the disc chord with the two-zone λ_g profile applied.
  const N = 1000;  // integration steps
  const rA = discRadius(latA), rB = discRadius(latB);
  const tA = discTheta(lonA), tB = discTheta(lonB);
  const xA = rA * Math.cos(tA), yA = rA * Math.sin(tA);
  const xB = rB * Math.cos(tB), yB = rB * Math.sin(tB);
  let total = 0;
  for (let i = 0; i < N; i++) {
    const t1 = i / N, t2 = (i + 1) / N;
    const x1 = xA + (xB - xA) * t1, y1 = yA + (yB - yA) * t1;
    const x2 = xA + (xB - xA) * t2, y2 = yA + (yB - yA) * t2;
    const rMid = Math.sqrt(((x1 + x2) / 2) ** 2 + ((y1 + y2) / 2) ** 2);
    const seg = Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
    total += seg * lambdaG(rMid);
  }
  return total;
}

module.exports = {
  v13FinslerDistance,
  inputs_are_dome_native: false,
  provenance: 'fit',
  provenance_note: 'LAMBDA_G_OUTER was tuned to reproduce the 4352 km Sydney-Perth observation; see EXP-085/091 archival history.',
  formula_id: 'FORM-V51-001',
  row_id: 'killshot-sydney-perth'
};

// Unit tests for v13-finsler-sydney-perth.js
// Pattern: each test is a synchronous assertion; the harness (test.js) collects failures.

const { v13FinslerDistance, inputs_are_dome_native, provenance } = require('./v13-finsler-sydney-perth');

const tests = [];

function assertClose(got, expected, tolKm, msg) {
  const diff = Math.abs(got - expected);
  tests.push({ name: msg, pass: diff <= tolKm, got, expected, diff, tolKm });
}

function assertEq(got, expected, msg) {
  tests.push({ name: msg, pass: got === expected, got, expected });
}

// 1. Sydney-Perth reproduces to 4352 km ± 0.5%.
const sydPer = v13FinslerDistance(-33.868, 151.209, -31.953, 115.857);
assertClose(sydPer, 4352, 22, 'Sydney-Perth distance within 0.5% of 4352 km');

// 2. Nullarbor control (Adelaide → Norseman ~1600 km surface): expect ~1600 km.
const adNor = v13FinslerDistance(-34.928, 138.600, -32.200, 121.777);
assertClose(adNor, 1600, 32, 'Adelaide-Norseman within 2% of surveyed ~1600 km');

// 3. Zero-distance symmetry.
const zero = v13FinslerDistance(-33.868, 151.209, -33.868, 151.209);
assertClose(zero, 0, 0.001, 'Zero distance when endpoints equal');

// 4. Metadata exposure.
assertEq(inputs_are_dome_native, false, 'inputs_are_dome_native flag is false (globe-pollution case)');
assertEq(provenance, 'fit', 'provenance is fit');

const failures = tests.filter(t => !t.pass);
if (failures.length) {
  console.error('FAIL: v13-finsler-sydney-perth');
  failures.forEach(f => console.error('  ', f));
  process.exit(1);
}
console.log(`PASS: ${tests.length} v13-finsler-sydney-perth tests`);

// θ = −lonE polar-azimuthal identity.
// Implements: V51.1 paper §2.1 coordinate convention; claim_index.json#win-058-theta-rule.
// Companion test file: theta-east-longitude.test.js
// inputs_are_dome_native: false — identity holds for any polar-azimuthal projection (globe-AE included).

function thetaFromLonE(lonE_deg) {
  // Dome convention: disc-angular coordinate θ equals the negated east longitude.
  // This is an algebraic identity under the polar-azimuthal projection class; it holds
  // for the globe's AE projection equally.
  return -lonE_deg;
}

function isNearIdentityTransform() {
  // This function is what guardrail G2 (globe-pollution detection) checks.
  // Return true if the mapping from globe coordinates to dome coordinates is an identity
  // (or differs only by sign/offset). Here: θ = −lonE is exactly a sign flip ⇒ near-identity.
  return true;
}

module.exports = {
  thetaFromLonE,
  isNearIdentityTransform,
  inputs_are_dome_native: false,
  provenance: 'forward_with_globe_inputs',
  provenance_note: 'Sign-flip identity; holds for any polar-azimuthal projection (AE, EA, etc.).',
  row_id: 'win-058-theta-rule'
};

const { thetaFromLonE, isNearIdentityTransform, inputs_are_dome_native } = require('./theta-east-longitude');

const tests = [];
function assertEq(got, expected, msg) { tests.push({ name: msg, pass: got === expected, got, expected }); }

assertEq(thetaFromLonE(0), 0, 'lonE=0 → θ=0');
assertEq(thetaFromLonE(90), -90, 'lonE=90 → θ=−90');
assertEq(thetaFromLonE(-180), 180, 'lonE=−180 → θ=180');
assertEq(isNearIdentityTransform(), true, 'mapping flagged as near-identity (G2 guardrail trip)');
assertEq(inputs_are_dome_native, false, 'inputs_are_dome_native=false');

const failures = tests.filter(t => !t.pass);
if (failures.length) {
  console.error('FAIL: theta-east-longitude');
  failures.forEach(f => console.error('  ', f));
  process.exit(1);
}
console.log(`PASS: ${tests.length} theta-east-longitude tests`);
